import base64
from openai import OpenAI

client = OpenAI()  # reads OPENAI_API_KEY from environment

# Option 1: URL reference (image must be publicly reachable)
response_url = client.chat.completions.create(
    model="gpt-4o",
    messages=[
        {
            "role": "user",
            "content": [
                {
                    "type": "image_url",
                    "image_url": {
                        "url": "https://example.com/chart.png",
                        "detail": "high",  # or "low" or "auto"
                    },
                },
                {"type": "text", "text": "Describe the trend shown in this chart."},
            ],
        }
    ],
    max_tokens=512,
)
print(response_url.choices[0].message.content)

# Option 2: base64-encoded local file
with open("diagram.png", "rb") as f:
    b64 = base64.b64encode(f.read()).decode()

response_b64 = client.chat.completions.create(
    model="gpt-4o",
    messages=[
        {
            "role": "user",
            "content": [
                {
                    "type": "image_url",
                    "image_url": {
                        "url": f"data:image/png;base64,{b64}",
                        "detail": "low",
                    },
                },
                {"type": "text", "text": "What is in this image?"},
            ],
        }
    ],
    max_tokens=256,
)
print(response_b64.choices[0].message.content)

import torch
import torch.nn as nn
from transformers import CLIPVisionModel

class LLaVAConnector(nn.Module):
    """The 2-layer MLP that bridges CLIP features to the LLM embedding space."""
    def __init__(self, vision_hidden: int = 1024, llm_hidden: int = 4096):
        super().__init__()
        self.proj = nn.Sequential(
            nn.Linear(vision_hidden, llm_hidden),
            nn.GELU(),
            nn.Linear(llm_hidden, llm_hidden),
        )

    def forward(self, image_features: torch.Tensor) -> torch.Tensor:
        # image_features: (batch, 576, 1024)  ← from CLIP ViT-L/14@336
        return self.proj(image_features)       # (batch, 576, 4096)


class LLaVAVisionTower(nn.Module):
    """CLIP ViT-L/14 at 336 px: returns penultimate-layer hidden states."""
    def __init__(self):
        super().__init__()
        self.clip = CLIPVisionModel.from_pretrained("openai/clip-vit-large-patch14-336")
        # Freeze by default — fine-tuning is optional
        for p in self.clip.parameters():
            p.requires_grad = False

    def forward(self, pixel_values: torch.Tensor) -> torch.Tensor:
        # pixel_values: (B, 3, 336, 336)
        outputs = self.clip(pixel_values=pixel_values, output_hidden_states=True)
        # Drop the [CLS] token; use all 576 patch tokens from the last hidden state
        return outputs.hidden_states[-2][:, 1:, :]  # (B, 576, 1024)

import base64
from openai import OpenAI

client = OpenAI()

def load_b64(path: str) -> str:
    with open(path, "rb") as f:
        return base64.b64encode(f.read()).decode()

# Compare two plots from an A/B experiment
response = client.chat.completions.create(
    model="gpt-4o",
    messages=[
        {
            "role": "user",
            "content": [
                {
                    "type": "image_url",
                    "image_url": {"url": f"data:image/png;base64,{load_b64('control.png')}", "detail": "low"},
                },
                {
                    "type": "image_url",
                    "image_url": {"url": f"data:image/png;base64,{load_b64('treatment.png')}", "detail": "low"},
                },
                {
                    "type": "text",
                    "text": "The first image is the control group result, the second is the treatment. "
                            "What changed and is the improvement statistically meaningful?",
                },
            ],
        }
    ],
    max_tokens=512,
)
print(response.choices[0].message.content)
print(f"Total image tokens: {2 * 85} (both detail=low)")
